  mutations: {
    del(state, id) {
      state.teams = state.teams.filter(team => {
        return team.id !== id;
      });
    },
    add(state, newTeam) {
      newTeam.id = Math.random();
      state.teams = [...state.teams, newTeam];
    },
    team(state, id) {
      state.teams = state.teams.filter(team => {
        return team.id == id;
      });
    },
    update(state, team) {
      state.teams.filter(t => {
        if (t.id == team.id) {
          t.name = team.name;
          t.email = team.email;
          t.position = team.position;
          t.skills = team.skills;
        }
      });
    }
  },
