import Vue from "vue";
import Router from "vue-router";
import Meta from "vue-meta";
import Home from "./views/";
import About from "./views/about/";
import Blog from "./views/blog/";
import BlogDetail from "./views/blog/_id";
import Portfolio from "./views/portfolio/";
import Itunes from "./views/portfolio/itunes";
import Crud from "./views/portfolio/crud/index";
import CrudID from "./views/portfolio/crud/_id";

Vue.use(Router);
Vue.use(Meta, {
  keyName: "metaInfo",
  attribute: "data-vue-meta",
  ssrAttribute: "data-vue-meta-server-rendered",
  tagIDKeyName: "vmid"
});

export default new Router({
  mode: "history",
  base: process.env.BASE_URL,
  routes: [
    {
      path: "/",
      name: "home",
      component: Home
    },
    {
      path: "/portfolio",
      name: "portfolio",
      component: Portfolio
    },
    {
      path: "/blog",
      name: "blog",
      component: Blog
    },
    {
      path: "/blog/:id",
      name: "blog-detail",
      component: BlogDetail
    },
    {
      path: "/itunes",
      name: "itunes",
      component: Itunes
    },
    {
      path: "/crud",
      name: "crud",
      component: Crud
    },
    {
      path: "/crud/:id",
      name: "crud-id",
      component: CrudID
    },
    {
      path: "/about",
      name: "about",
      component: About
    }
  ]
});
